svg.script:
(function(){
  var svg = document.currentScript.closest('svg');
  if (!svg) return;

  // Find all animated elements (those with _tr suffix IDs and the fill animation)
  var targets = svg.querySelectorAll('[id*="_tr"], [id*="e5kQjlZz4ry18"]');

  function restartAnimations() {
    targets.forEach(function(el) {
      el.style.animation = 'none';
      el.style.animation = ''; // reset to CSS
    });
    // Force reflow then re-add
    void svg.offsetWidth;
    targets.forEach(function(el) {
      el.style.animation = '';
    });
  }

  // On hover: restart
  svg.addEventListener('mouseenter', restartAnimations);

  // On load: animations already play 3 times via CSS
})();
